function findCheapestPrice(n, flights, src, dst, k) {
    const graph = Array.from({ length: n }, () => []);
    for (const flight of flights) {
        graph[flight[0]].push([flight[1], flight[2]]);
    }

    const pq = [[0, src, k + 1]];
    while (pq.length) {
        pq.sort((a, b) => a[0] - b[0]);
        const [price, city, stops] = pq.shift();

        if (city === dst) {
            return price;
        }

        if (stops > 0) {
            for (const [nei, prc] of graph[city]) {
                pq.push([price + prc, nei, stops - 1]);
            }
        }
    }

    return -1;
}
```


    1. Create an adjacency list called `graph` to represent the flights’ connections.
2. Create a min-heap(priority queue) `pq`, and add the starting city `src` with a price of 0, and stops equal to `k+1`.
3. While the priority queue is not empty, do the following:
   - Pop the next item(price, city, stops) from `pq`.
   - If the city is the destination `dst`, return the price.
   - If there are stops remaining, iterate through neighbors, push the neighbor city with an updated price and decreased stops to the priority queue.
4. If the loop finishes and no valid route was found, return -1.

solutionCode.java:
    ```java
import java.util.*;

public int findCheapestPrice(int n, int[][] flights, int src, int dst, int k) {
    List<List<int[]>> graph = new ArrayList<>();
    for (int i = 0; i < n; i++)
        graph.add(new ArrayList<>());
    for (int[] flight : flights)
        graph.get(flight[0]).add(new int[]{ flight[1], flight[2] });

    PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[0] - b[0]);
    pq.offer(new int[]{0, src, k + 1});

    while (!pq.isEmpty()) {
        int[] info = pq.poll();
        int price = info[0], city = info[1], stops = info[2];

        if (city == dst)
            return price;

        if (stops > 0) {
            for (int[] neighbor : graph.get(city))
                pq.offer(new int[]{ price + neighbor[1], neighbor[0], stops - 1 });
        }
    }

    return -1;
}
```


    1. Create an adjacency list called `graph` to represent the flights’ connections.
2. Create a min-heap(priority queue) `pq`, and add the starting city `src` with a price of 0, and stops equal to `k+1`.
3. While the priority queue is not empty, do the following:
   - Pop the next item(price, city, stops) from `pq`.
   - If the city is the destination `dst`, return the price.
   - If there are stops remaining, iterate through neighbors, push the neighbor city with an updated price and decreased stops to the priority queue.
4. If the loop finishes and no valid route was found, return -1.
